from database import Database

class Publicacion:
    def __init__(self, db_name):
        self.db = Database(db_name)
        self.conn = self.db.connect()

    def create_table(self, table_name):
        if not table_name:
            raise ValueError("El nombre de la tabla no puede ser vacío")

        query = f"""
            CREATE TABLE IF NOT EXISTS {table_name} (
                id INTEGER PRIMARY KEY,
                titulo TEXT NOT NULL,
                contenido TEXT NOT NULL
            );
        """
        self.db.execute_query(query)

    def insert_data(self, table_name, data):
        if not table_name or not data:
            raise ValueError("El nombre de la tabla y los datos no pueden ser vacíos")

        query = f"""
            INSERT INTO {table_name} (titulo, contenido)
            VALUES (?, ?);
        """
        self.db.execute_query(query, data)

    def get_usuario(self, table_name, id):
        if not table_name or not id:
            raise ValueError("El nombre de la tabla y el id no pueden ser vacíos")

        query = f"""
            SELECT * FROM {table_name}
            WHERE id = ?;
        """
        cursor = self.db.execute_query(query, (id,))
        row = cursor.fetchone()
        if row:
            return row
        else:
            return None

    def close_connection(self):
        self.db.close_connection()


