from typing import Dict, List, Optional

class SchemaResolver:
    """
    Clase para resolver referencias en un esquema.
    """

    def __init__(self, schema: Dict):
        """
        Inicializa el resolutor de esquemas.

        Args:
        - schema (Dict): El esquema a resolver.
        """
        self.schema = schema
        self.visited_schemas: set = set()

    def _resolve_ref(self, ref: str) -> Optional[Dict]:
        """
        Resuelve una referencia en el esquema.

        Args:
        - ref (str): La referencia a resolver.

        Returns:
        - Optional[Dict]: El esquema resuelto o None si no se encuentra.
        """
        if not ref:
            return None

        # Verifica si la referencia es un objeto
        if isinstance(ref, dict):
            return ref

        # Verifica si la referencia es una cadena
        if isinstance(ref, str):
            # Verifica si la referencia es a un esquema que no existe
            if ref not in self.schema:
                return None

            # Verifica si el esquema ya ha sido visitado
            if ref in self.visited_schemas:
                return None

            # Agrega el esquema a la lista de visitados
            self.visited_schemas.add(ref)

            # Resuelve la referencia
            return self.schema[ref]

        return None

    def resolve(self) -> Dict:
        """
        Resuelve todas las referencias en el esquema.

        Returns:
        - Dict: El esquema resuelto.
        """
        if not self.schema:
            return {}

        resolved_schema: Dict = {}

        # Recorre el esquema en busca de referencias
        for key, value in self.schema.items():
            if isinstance(value, dict):
                # Resuelve las referencias en el valor
                resolved_value = self._resolve_ref(value)
                if resolved_value:
                    resolved_schema[key] = resolved_value
                else:
                    resolved_schema[key] = value
            else:
                resolved_schema[key] = value

        return resolved_schema


def main():
    # Ejemplo de uso
    schema: Dict = {
        "esquema1": {
            "referencia": "esquema2"
        },
        "esquema2": {
            "propiedad": "valor"
        }
    }

    resolver = SchemaResolver(schema)
    resolved_schema = resolver.resolve()
    print(resolved_schema)


if __name__ == "__main__":
    main()
