class Nodo:
    """Representa un nodo en el árbol."""
    def __init__(self, valor):
        """Inicializa un nodo con un valor."""
        self.valor = valor
        self.hijos = []

class Arbol:
    """Representa un árbol."""
    def __init__(self, raiz=None):
        """Inicializa un árbol con una raíz."""
        self.raiz = raiz

    def serializar(self):
        """Serializa el árbol en una cadena."""
        if self.raiz is None:
            return ""

        resultado = []
        self._serializar_nodo(self.raiz, resultado)
        return "".join(resultado)

    def _serializar_nodo(self, nodo, resultado):
        """Serializa un nodo y sus hijos."""
        resultado.append(str(nodo.valor))
        if nodo.hijos:
            resultado.append("(")
            for hijo in nodo.hijos:
                self._serializar_nodo(hijo, resultado)
                resultado.append(",")
            resultado[-1] = ")"  # Reemplaza la última coma con un paréntesis

    @staticmethod
    def deserializar(cadena):
        """Deserializa una cadena en un árbol."""
        if not cadena:
            return Arbol()

        valores = []
        Arbol._deserializar_cadena(cadena, valores)
        return Arbol._deserializar_valores(valores)

    @staticmethod
    def _deserializar_cadena(cadena, valores):
        """Deserializa una cadena en una lista de valores."""
        pila = []
        for caracter in cadena:
            if caracter.isdigit():
                pila.append(caracter)
            elif caracter == "(":
                pila.append(caracter)
            elif caracter == ")":
                valores.append("".join(pila))
                pila = []
            elif caracter == ",":
                if pila:
                    valores.append("".join(pila))
                    pila = []

    @staticmethod
    def _deserializar_valores(valores):
        """Deserializa una lista de valores en un árbol."""
        if not valores:
            return Arbol()

        raiz = Nodo(int(valores[0]))
        pila = [raiz]
        indice = 1
        while indice < len(valores):
            valor = valores[indice]
            if valor.startswith("("):
                nodo = Nodo(int(valor[1:-1]))
                pila[-1].hijos.append(nodo)
                pila.append(nodo)
            elif valor.endswith(")"):
                pila.pop()
            indice += 1
        return Arbol(raiz)

# Ejemplo de uso
arbol = Arbol(Nodo(1))
arbol.raiz.hijos = [Nodo(2), Nodo(3)]
arbol.raiz.hijos[0].hijos = [Nodo(4), Nodo(5)]

cadena = arbol.serializar()
print(cadena)  # Salida: "1(2(4,5),3)"

nuevo_arbol = Arbol.deserializar(cadena)
print(nuevo_arbol.serializar())  # Salida: "1(2(4,5),3)"
