from enum import Enum
from typing import List, Union

class TokenTipo(Enum):
    """Tipos de tokens"""
    NUMERO = 1
    OPERADOR = 2
    PARENTECIS = 3

class Token:
    """Representa un token en la expresión"""
    def __init__(self, tipo: TokenTipo, valor: str):
        """
        Inicializa un token con su tipo y valor

        :param tipo: Tipo del token
        :param valor: Valor del token
        """
        self.tipo = tipo
        self.valor = valor

    def __repr__(self) -> str:
        """Representación como cadena del token"""
        return f'Token({self.tipo}, {self.valor})'

class Lexer:
    """Analizador léxico de la expresión"""
    def __init__(self, texto: str):
        """
        Inicializa el analizador léxico con el texto a analizar

        :param texto: Texto a analizar
        """
        self.texto = texto
        self.posicion = 0
        self.token_actual = None

    def obtener_siguiente_token(self) -> Token:
        """
        Obtiene el siguiente token en el texto

        :return: Token obtenido
        """
        # Salta espacios en blanco
        while self.posicion < len(self.texto) and self.texto[self.posicion].isspace():
            self.posicion += 1

        # Fin del texto
        if self.posicion >= len(self.texto):
            return Token(TokenTipo.PARENTECIS, None)

        caracter_actual = self.texto[self.posicion]

        # Número
        if caracter_actual.isdigit() or caracter_actual == '.':
            inicio = self.posicion
            while self.posicion < len(self.texto) and (self.texto[self.posicion].isdigit() or self.texto[self.posicion] == '.'):
                self.posicion += 1
            return Token(TokenTipo.NUMERO, self.texto[inicio:self.posicion])

        # Operador o paréntesis
        if caracter_actual in '+-*/()':
            self.posicion += 1
            if caracter_actual in '+-*/':
                return Token(TokenTipo.OPERADOR, caracter_actual)
            else:
                return Token(TokenTipo.PARENTECIS, caracter_actual)

        # Caracter no reconocido
        raise Exception(f'Caracter no reconocido: {caracter_actual}')

    def avanzar(self) -> None:
        """Avanza al siguiente token"""
        self.token_actual = self.obtener_siguiente_token()

class Nodo:
    """Nodo en el árbol de expresión"""
    def __init__(self, valor: Union[int, float, str]):
        """
        Inicializa un nodo con su valor

        :param valor: Valor del nodo
        """
        self.valor = valor

def main() -> None:
    lexer = Lexer("2 + 3 * 4")
    while True:
        lexer.avanzar()
        token = lexer.token_actual
        if token.tipo == TokenTipo.PARENTECIS and token.valor is None:
            break
        print(token)

if __name__ == "__main__":
    main()
