import json

def resolver_referencia(esquema, clave):
    """
    Resuelve una referencia circular en el esquema.

    Args:
        esquema (dict): El esquema que contiene la referencia circular.
        clave (str): La clave que se busca en el esquema.

    Returns:
        dict: El valor asociado a la clave en el esquema.
    """
    if clave not in esquema:
        raise ValueError(f"La clave '{clave}' no existe en el esquema")
    return esquema[clave]

def resolver_referencias(esquema, valor):
    """
    Resuelve las referencias circulares en el valor.

    Args:
        esquema (dict): El esquema que contiene las referencias circulares.
        valor: El valor que se busca resolver.

    Returns:
        dict: El valor resuelto.
    """
    if isinstance(valor, list):
        return [resolver_referencias(esquema, item) for item in valor]
    elif isinstance(valor, dict):
        return {clave: resolver_referencias(esquema, valor[clave]) for clave in valor}
    elif isinstance(valor, str) and valor.startswith("$ref"):
        clave = valor.split("/")[-1]
        return resolver_referencia(esquema, clave)
    else:
        return valor

def validar_json_con_esquema(esquema, json_data):
    """
    Valida un JSON con un esquema que puede contener referencias circulares.

    Args:
        esquema (dict): El esquema que se utiliza para validar el JSON.
        json_data (dict): El JSON que se busca validar.

    Returns:
        bool: True si el JSON es válido, False en caso contrario.
    """
    if esquema is None or json_data is None:
        raise ValueError("El esquema y el JSON no pueden ser None")
    try:
        json.loads(json.dumps(esquema))
        json.loads(json.dumps(json_data))
    except json.JSONDecodeError as e:
        raise ValueError(f"El esquema o el JSON están mal formados: {e}")
    return resolver_referencias(esquema, json_data) == json_data

# Ejemplo de uso
esquema = {
    "type": "object",
    "properties": {
        "nombre": {"type": "string"},
        "edad": {"type": "integer"},
        "amigos": {"type": "array", "items": {"$ref": "#/properties/amigo"}}
    },
    "definitions": {
