import sys
import heapq

def bellman_ford(grafo, origen):
    """
    Algoritmo de Bellman-Ford para detectar ciclos negativos.

    Args:
        grafo (dict): Grafo representado como un diccionario de adyacencia.
        origen (str): Vértice de origen.

    Returns:
        bool: True si hay un ciclo negativo, False en caso contrario.
    """
    distancia = {vertice: sys.maxsize for vertice in grafo}
    distancia[origen] = 0

    for _ in range(len(grafo) - 1):
        for vertice in grafo:
            for adyacente, peso in grafo[vertice].items():
                if distancia[vertice] + peso < distancia[adyacente]:
                    distancia[adyacente] = distancia[vertice] + peso

    for vertice in grafo:
        for adyacente, peso in grafo[vertice].items():
            if distancia[vertice] + peso < distancia[adyacente]:
                return True

    return False


def dijkstra(grafo, origen, destino):
    """
    Algoritmo de Dijkstra para encontrar el camino más corto.

    Args:
        grafo (dict): Grafo representado como un diccionario de adyacencia.
        origen (str): Vértice de origen.
        destino (str): Vértice de destino.

    Returns:
        list: Camino más corto desde el vértice de origen al vértice de destino.
    """
    if origen not in grafo or destino not in grafo:
        raise ValueError("Vértice de origen o destino no existe en el grafo")

    distancia = {vertice: sys.maxsize for vertice in grafo}
    distancia[origen] = 0
    padre = {vertice: None for vertice in grafo}

    cola = [(0, origen)]

    while cola:
        _, vertice = heapq.heappop(cola)

        for adyacente, peso in grafo[vertice].items():
            if distancia[vertice] + peso < distancia[adyacente]:
                distancia[adyacente] = distancia[vertice] + peso
                padre[adyacente] = vertice
                heapq.heappush(cola, (distancia[adyacente], adyacente))

    camino = []
    vertice = destino

    while vertice is not None:
        camino.append(vertice)
        vertice = padre[vertice]

    return camino[::-1]


def verificar_ciclos_negativos(grafo):
    """
    Verifica si hay ciclos negativos en el grafo.

    Args:
        grafo (dict): Grafo representado como un diccionario de adyacencia.

    Returns:
        bool: True si hay un ciclo negativo, False en caso contrario.
    """
    for vertice in grafo:
        if bellman_ford(grafo, vertice):
            return True

    return False


