def backoff_exponencial(retry_count: int, initial_backoff: int = INITIAL_BACKOFF, backoff_multiplier: int = BACKOFF_MULTIPLIER) -> float:
    return initial_backoff * (backoff_multiplier ** retry_count)

def sistema_de_retry(max_retries: int = MAX_RETRIES, circuit_breaker: CircuitBreaker = None) -> Callable:
    def decorador(func: Callable) -> Callable:
        def wrapper(*args, **kwargs):
            retry_count = 0
            while retry_count <= max_retries:
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    logger.error(f"Error en la llamada al servicio: {e}")
                    if circuit_breaker and circuit_breaker.is_open():
                        logger.info("Circuito breaker abierto, esperando...")
                        time.sleep(circuit_breaker._timeout)
                    else:
                        retry_count += 1
                        if retry_count > max_retries:
                            logger.error("Máximo número de reintentos alcanzado")
                            raise
                        backoff = backoff_exponencial(retry_count)
                        logger.info(f"Reintento {retry_count} en {backoff} segundos")
                        time.sleep(backoff)
                        if random.random() < 0.5:  # Simulación de fallo
                            circuit_breaker.open()
                            logger.info("Circuito breaker abierto")
            raise Exception("Máximo número de reintentos alcanzado")
        return wrapper
    return decorador

@circuit_breaker
def servicio_externo_simulado() -> None:
    if random.random() < 0.5:  # Simulación de fallo
        raise Exception("Error en el servicio externo")
    logger.info("Servicio externo simulado llamado con éxito")

