        resultado = self.parsear_termino()
        while self.token_actual.tipo == "OPERADOR" and self.token_actual.valor in "+-":
            if self.token_actual.valor == "+":
                self.token_actual = self.lexer.obtener_token()
                resultado += self.parsear_termino()
            elif self.token_actual.valor == "-":
                self.token_actual = self.lexer.obtener_token()
                resultado -= self.parsear_termino()
        return resultado

    def parsear_termino(self) -> float:
