    numero = ""
    for char in expresion:
        if char.isdigit() or char == "." or char == "-":
            numero += char
        else:
            if numero:
                tokens.append(numero)
                numero = ""
            if char in "+-*/()":
                tokens.append(char)
            else:
                raise ValueError("La expresión matemática contiene caracteres no válidos")
    if numero:
        tokens.append(numero)

    return tokens


def infix_to_rpn(tokens):
    """
    Convierte la expresión matemática de notación infija a notación polaca inversa (RPN).

    Args:
        tokens (list): La lista de tokens (números y operadores) de la expresión matemática.

    Returns:
        list: La lista de tokens en notación polaca inversa (RPN).

    Raises:
        ValueError: Si la expresión matemática tiene paréntesis no balanceados.
    """
    operadores = deque()
    rpn = []
    precedencia = {"+": 1, "-": 1, "*": 2, "/": 2}

    for token in tokens:
        if token.isdigit() or (token.startswith("-") and token[1:].isdigit()):
            rpn.append(token)
        elif token in precedencia:
            while (operadores and
                   operadores[-1] in precedencia and
                   precedencia[operadores[-1]] >= precedencia[token]):
                rpn.append(operadores.pop())
            operadores.append(token)
        elif token == "(":
            operadores.append(token)
        elif token == ")":
            while operadores and operadores[-1] != "(":
                rpn.append(operadores.pop())
            if not operadores or operadores[-1] != "(":
                raise ValueError("La expresión matemática tiene paréntesis no balanceados")
            operadores.pop()

    while operadores:
        rpn.append(operadores.pop())

    return rpn


def evaluar_rpn(rpn):
    """
    Evalúa la expresión matemática en notación polaca inversa (RPN).

    Args:
        rpn (list): La lista de tokens en notación polaca inversa (RPN).

    Returns:
        float: El resultado de la evaluación de la expresión matemática.

    Raises:
        ZeroDivisionError: Si se intenta dividir por cero.
    """
    pila = deque()

    for token in rpn:
        if token.replace("-", "", 1).replace(".", "", 1).isdigit():
            pila.append(float(token))
        else:
            operando2 = pila.pop()
