import requests
import time
import logging
from typing import Optional, Dict

class CircuitBreaker:
    def __init__(self, threshold: int = 3, timeout: int = 30):
        self.threshold = threshold
        self.timeout = timeout
        self.failures = 0
        self.opened_at = None

    def is_open(self) -> bool:
        return self.opened_at is not None

    def open(self) -> None:
        self.opened_at = time.time()

    def close(self) -> None:
        self.opened_at = None
        self.failures = 0

    def try_execute(self, func: callable, *args, **kwargs) -> Optional[Dict]:
        if self.is_open():
            if time.time() - self.opened_at > self.timeout:
                self.close()
            else:
                return None

        try:
            result = func(*args, **kwargs)
            self.failures = 0
            return result
        except requests.RequestException as e:
            self.failures += 1
            if self.failures >= self.threshold:
                self.open()
            logging.error(f"Error en la solicitud: {e}")
            return None

class Backoff:
    def __init__(self, initial_delay: int = 1, max_delay: int = 30, factor: int = 2):
        self.initial_delay = initial_delay
        self.max_delay = max_delay
        self.factor = factor
        self.delay = initial_delay

    def reset(self) -> None:
        self.delay = self.initial_delay

    def increase_delay(self) -> None:
        self.delay = min(self.delay * self.factor, self.max_delay)

    def wait(self) -> None:
        time.sleep(self.delay)

def solicitar_api(url: str, params: Optional[Dict] = None) -> Optional[Dict]:
    if url is None or params is None:
        logging.error("URL o parámetros no pueden ser None")
        return None

    circuit_breaker = CircuitBreaker()
    backoff = Backoff()

    while True:
        response = circuit_breaker.try_execute(requests.get, url, params=params)
        if response is not None:
            try:
                return response.json()
            except ValueError:
                logging.error("Respuesta no es JSON")
                backoff.increase_delay()
                backoff.wait()
        else:
            backoff.increase_delay()
            backoff.wait()

def main() -> None:
    url = "https://api.example.com/endpoint"
    params = {"param1": "valor1", "param2": "valor2"}
    response = solicitar_api(url, params)
    if response is not None:
        print(response)
    else:
        print("Solicitud fallida")

