import functools

class Cache:
    def __init__(self):
        self.cache = {}
        self.dependencias = {}

    def obtener_resultado(self, funcion, args, kwargs):
        """Obtiene el resultado de una función desde el caché."""
        clave = (funcion.__name__, args, frozenset(kwargs.items()))
        if clave in self.cache:
            return self.cache[clave]
        resultado = funcion(*args, **kwargs)
        self.cache[clave] = resultado
        return resultado

    def registrar_dependencia(self, funcion, dependencia):
        """Registra una dependencia para una función."""
        if funcion.__name__ not in self.dependencias:
            self.dependencias[funcion.__name__] = set()
        self.dependencias[funcion.__name__].add(dependencia.__name__)

    def invalidar_dependencias(self, funcion):
        """Invalida las dependencias de una función."""
        if funcion.__name__ in self.dependencias:
            for dependencia in self.dependencias[funcion.__name__]:
                self.invalidar_cache(dependencia)

    def invalidar_cache(self, funcion):
        """Invalida el caché de una función."""
        if funcion.__name__ in self.cache:
            del self.cache[funcion.__name__]

def cache(funcion):
    """Decorador que implementa un mecanismo de caché."""
    cache_instancia = Cache()

    @functools.wraps(funcion)
    def wrapper(*args, **kwargs):
        return cache_instancia.obtener_resultado(funcion, args, kwargs)

    def registrar_dependencia(dependencia):
        cache_instancia.registrar_dependencia(funcion, dependencia)

    def invalidar_cache():
        cache_instancia.invalidar_cache(funcion.__name__)

    wrapper.registrar_dependencia = registrar_dependencia
    wrapper.invalidar_cache = invalidar_cache
    return wrapper

# Ejemplo de uso
