def group_by_emulator(iterable, clave):
    """
    Emula la función groupby de la biblioteca itertools, agrupando los elementos de un iterable según una clave de función.

    Args:
        iterable: El iterable a agrupar.
        clave: La función que se utiliza para determinar la clave de agrupación.

    Yields:
        Tuplas conteniendo la clave de agrupación y una lista de elementos que pertenecen a ese grupo.
    """
    if iterable is None:
        raise ValueError("El iterable no puede ser None")

    if not iterable:
        return

    current_key = None
    current_group = []

    for elemento in iterable:
        key = clave(elemento)
        if key is None:
            raise ValueError("La función clave no puede devolver None")

        if key != current_key:
            if current_key is not None:
                yield (current_key, current_group)
            current_key = key
            current_group = [elemento]
        else:
            current_group.append(elemento)

    if current_key is not None:
        yield (current_key, current_group)
