            raise ValueError("La entrada ya existe en la caché")
        self.cache[nombre] = resultado
        self.grafo.add_node(nombre)

    def eliminar_entrada(self, nombre: str) -> None:
        """Elimina una entrada de la caché y del grafo."""
        if nombre not in self.cache:
            raise ValueError("La entrada no existe en la caché")
        self.cache.pop(nombre)
        self._invalidar_entrada(nombre)

    def _invalidar_entrada(self, nombre: str) -> None:
        """Invalida una entrada y sus sucesores."""
        if nombre not in self.grafo:
            return
        sucesores = list(self.grafo.successors(nombre))
        self.grafo.remove_node(nombre)
        for sucesor in sucesores:
            self._invalidar_entrada(sucesor)

    def actualizar_entrada(self, nombre: str, nuevo_resultado: Any) -> None:
        """Actualiza el resultado de una entrada en la caché."""
        if nombre not in self.cache:
            raise ValueError("La entrada no existe en la caché")
        self.cache[nombre] = nuevo_resultado

    def obtener_resultado(self, nombre: str) -> Any:
        """Obtiene el resultado de una entrada en la caché."""
        if nombre not in self.cache:
            raise ValueError("La entrada no existe en la caché")
        return self.cache[nombre]
