import sys
import heapq

def bellman_ford(grafo, origen):
    """
    Algoritmo de Bellman-Ford para encontrar el camino más corto desde un nodo de origen a todos los demás nodos en un grafo.

    Args:
        grafo (dict): Representación del grafo como un diccionario de adyacencia.
        origen (str): Nodo de origen.

    Returns:
        dict: Distancias mínimas desde el nodo de origen a todos los demás nodos.
        dict: Predecesores de cada nodo en el camino más corto.
    """
    if not grafo:
        raise ValueError("El grafo está vacío")

    if origen not in grafo:
        raise ValueError("El nodo de origen no está en el grafo")

    distancias = {nodo: float('inf') for nodo in grafo}
    distancias[origen] = 0

    predecesores = {nodo: None for nodo in grafo}

    for _ in range(len(grafo) - 1):
        for nodo, vecinos in grafo.items():
            for vecino, peso in vecinos.items():
                if distancias[nodo] + peso < distancias[vecino]:
                    distancias[vecino] = distancias[nodo] + peso
                    predecesores[vecino] = nodo

    for nodo, vecinos in grafo.items():
        for vecino, peso in vecinos.items():
            if distancias[nodo] + peso < distancias[vecino]:
                raise ValueError("El grafo contiene un ciclo negativo")

    return distancias, predecesores


def dijkstra(grafo, origen):
    """
    Algoritmo de Dijkstra para encontrar el camino más corto desde un nodo de origen a todos los demás nodos en un grafo.

    Args:
        grafo (dict): Representación del grafo como un diccionario de adyacencia.
        origen (str): Nodo de origen.

    Returns:
        dict: Distancias mínimas desde el nodo de origen a todos los demás nodos.
        dict: Predecesores de cada nodo en el camino más corto.
    """
    if not grafo:
        raise ValueError("El grafo está vacío")

    if origen not in grafo:
        raise ValueError("El nodo de origen no está en el grafo")

    distancias = {nodo: float('inf') for nodo in grafo}
    distancias[origen] = 0

    predecesores = {nodo: None for nodo in grafo}

    cola_prioridad = [(0, origen)]

    while cola_prioridad:
        distancia_actual, nodo_actual = heapq.heappop(cola_prioridad)

        if distancia_actual > distancias[nodo_actual]:
            continue

        for vecino, peso in grafo[nodo_actual].items():
            distancia_vecino = distancia_actual + peso

            if distancia_vecino < distancias[vecino]:
                distancias[vecino] = distancia_vecino
                predecesores[vecino] = nodo_actual
                heapq.heappush(cola_prioridad, (distancia_vecino, vecino))

    return distancias, predecesores


def main():
    grafo = {
        'A': {'B': 1, 'C': 4},
        'B': {'A': 1, 'C': 2, 'D': 5},
        'C': {'A': 4, 'B': 2, 'D': 1},
        'D': {'B': 5, 'C': 1}
    }

    origen = 'A'

    try:
        distancias, predecesores = bellman_ford(grafo, origen)
        print("Distancias mínimas:", distancias)
        print("Predecesores:", predecesores)
    except ValueError as e:
        print("Error:", e)

    try:
        distancias, predecesores = dijkstra(grafo, origen)
        print("Distancias mínimas:", distancias)
        print("Predecesores:", predecesores)
    except ValueError as e:
        print("Error:", e)


