import sqlite3

logging.basicConfig(level=logging.INFO)

class PoolConexiones:
    def __init__(self, num_conexiones, timeout_inactividad):
        self.num_conexiones = num_conexiones
        self.timeout_inactividad = timeout_inactividad
        self.conexiones = queue.Queue(num_conexiones)
        self.lock = threading.Lock()

        for _ in range(num_conexiones):
            try:
                conexion = sqlite3.connect('basedatos.db')
                self.conexiones.put(conexion)
            except sqlite3.Error as e:
                logging.error(f'Error al crear conexión: {e}')

    def obtener_conexion(self):
        try:
            return self.conexiones.get(timeout=self.timeout_inactividad)
        except queue.Empty:
            logging.warning('No hay conexiones disponibles')
            return None

    def devolver_conexion(self, conexion):
        try:
            self.conexiones.put(conexion, timeout=self.timeout_inactividad)
        except queue.Full:
            logging.warning('No se puede devolver la conexión, cola llena')

    def cerrar(self):
        with self.lock:
            while not self.conexiones.empty():
                conexion = self.conexiones.get()
                try:
                    conexion.close()
                except sqlite3.Error as e:
                    logging.error(f'Error al cerrar conexión: {e}')

def gestionar_timeout(timeout):
    def decorador(func):
        def wrapper(*args, **kwargs):
            inicio = time.time()
            while True:
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    logging.error(f'Error al ejecutar función: {e}')
                    if time.time() - inicio > timeout:
                        raise TimeoutError('Tiempo de espera agotado')
                    time.sleep(1)
        return wrapper
    return decorador

@gestionar_timeout(10)
def ejecutar_query(conexion, query):
    cursor = conexion.cursor()
    try:
        cursor.execute(query)
        return cursor.fetchall()
    except sqlite3.Error as e:
        logging.error(f'Error al ejecutar query: {e}')
        raise

def worker(pool, query):
    try:
        conexion = pool.obtener_conexion()
        if conexion:
            resultado = ejecutar_query(conexion, query)
            pool.devolver_conexion(conexion)
            return resultado
    except Exception as e:
        logging.error(f'Error en worker: {e}')

def main():
    num_conexiones = 5
    timeout_inactividad = 5
    pool = PoolConexiones(num_conexiones, timeout_inactividad)

    queries = ['SELECT * FROM tabla1', 'SELECT * FROM tabla2']
    threads = []

    for query in queries:
        thread = threading.Thread(target=worker, args=(pool, query))
        thread.start()
        threads.append(thread)

    for thread in threads:
        thread.join()

    pool.cerrar()

if __name__ == '__main__':
    main()
