    def __init__(self, max_requests: int, window_size: int, bucket_size: int):
        if max_requests <= 0 or window_size <= 0:
            raise ValueError("max_requests y window_size deben ser valores positivos")
        self.max_requests = max_requests
        self.window_size = window_size
        self.bucket_size = bucket_size
        self.bucket: deque = deque()
        self.logger = Logger()

