class Lexer:
    def __init__(self, texto):
        self.texto = texto
        self.posicion = 0
        self.token_actual = None

    def skip_whitespace(self):
        while self.posicion < len(self.texto) and self.texto[self.posicion].isspace():
            self.posicion += 1

    def integer(self):
        resultado = 0
        while self.posicion < len(self.texto) and self.texto[self.posicion].isdigit():
            resultado = resultado * 10 + int(self.texto[self.posicion])
            self.posicion += 1
        return resultado

    def get_next_token(self):
        self.skip_whitespace()
        if self.posicion >= len(self.texto):
            return None
        caracter_actual = self.texto[self.posicion]
        if caracter_actual.isdigit():
            self.token_actual = self.integer()
            return "ENTERO"
        elif caracter_actual in "+-*/()":
            self.token_actual = caracter_actual
            self.posicion += 1
            return "SIMBOLO"
        else:
            raise ValueError(f"Caracter no reconocido: {caracter_actual}")

class Parser:
    def __init__(self, lexer):
        self.lexer = lexer
        self.token_actual = None

    def factor(self):
        token = self.lexer.get_next_token()
        if token == "ENTERO":
            resultado = self.lexer.token_actual
            return resultado
        elif token == "SIMBOLO" and self.lexer.token_actual == "(":
            resultado = self.expresion()
            token = self.lexer.get_next_token()
            if token != "SIMBOLO" or self.lexer.token_actual != ")":
                raise ValueError("Paréntesis no balanceados")
            return resultado
        else:
            raise ValueError("Token no reconocido")

    def expresion(self):
        resultado = self.factor()
        while True:
            token = self.lexer.get_next_token()
            if token != "SIMBOLO":
                self.lexer.posicion -= 1
                break
            simbolo = self.lexer.token_actual
            if simbolo in "+-":
                otro_factor = self.factor()
                if simbolo == "+":
                    resultado += otro_factor
                else:
                    resultado -= otro_factor
            elif simbolo in "*/":
                otro_factor = self.factor()
                if simbolo == "*":
                    resultado *= otro_factor
                else:
                    resultado /= otro_factor
        return resultado

def calcular_expresion(texto):
    lexer = Lexer(texto)
    parser = Parser(lexer)
    return parser.expresion()

