        if id(esquema) in self.visitados:
            raise ValidationError("Referencia circular detectada en el esquema")
        self.visitados.add(id(esquema))
        try:
            Draft7Validator.check_schema(esquema)
            validate(instance=datos, schema=esquema)
        finally:
            self.visitados.remove(id(esquema))

    def validar_con_ciclo(self, esquema, datos):
        try:
            self._validar_con_ciclo(esquema, datos)
            return True
        except (ValidationError, SchemaError) as e:
            print(f"Error: {e}")
            return False

    def _validar_con_ciclo(self, esquema, datos):
        if id(esquema) in self.visitados:
            raise ValidationError("Referencia circular detectada en el esquema")
        self.visitados.add(id(esquema))
        try:
            if "$ref" in esquema:
                ref = esquema["$ref"]
                if ref.startswith("#"):
                    subesquema = self._obtener_subesquema(esquema, ref)
                    self._validar_con_ciclo(subesquema, datos)
                else:
                    raise ValidationError("Referencia externa no soportada")
            else:
                Draft7Validator.check_schema(esquema)
                validate(instance=datos, schema=esquema)
        finally:
            self.visitados.remove(id(esquema))

    def _obtener_subesquema(self, esquema, ref):
        uri, fragmento = ref.split("#", 1)
        if uri == "":
            return self._buscar_subesquema(esquema, fragmento)
        else:
            raise ValidationError("Referencia externa no soportada")

    def _buscar_subesquema(self, esquema, fragmento):
        partes = fragmento.split("/")
        subesquema = esquema
        for parte in partes:
            if parte == "":
                continue
            if parte not in subesquema:
                raise ValidationError("Subesquema no encontrado")
            subesquema = subesquema[parte]
        return subesquema
