        :return: El esquema correspondiente.
        """
        if not isinstance(self.schema, dict):
            raise ValueError("El esquema debe ser un diccionario")

        parts = reference.split("/")
        current_schema = self.schema

        for part in parts[1:]:
            if part not in current_schema:
                raise ValueError(f"Referencia interna no encontrada: {reference}")
            current_schema = current_schema[part]

        return current_schema

    def _resolve_external_reference(self, reference):
        """
        Resuelve una referencia externa.

        :param reference: La referencia externa.
        :return: El esquema correspondiente.
        """
        parsed_url = urlparse(reference)
        if not parsed_url.scheme:
            raise ValueError(f"Referencia externa no válida: {reference}")

        # Carga el esquema desde la URL
        try:
            import requests
            response = requests.get(reference)
            response.raise_for_status()
            return response.json()
        except requests.RequestException as e:
            raise ValueError(f"Error al cargar la referencia externa: {e}")

    def _validate_schema(self, schema):
        """
        Valida un esquema.

        :param schema: El esquema a validar.
        :return: True si el esquema es válido, False de lo contrario.
        """
        if schema is None:
            raise ValueError("El esquema no puede ser None")

        if not isinstance(schema, dict):
            raise ValueError("El esquema debe ser un diccionario")

        if id(schema) in self.visited_schemas:
            raise CircularReferenceError(f"Referencia circular detectada: {schema}")

        self.visited_schemas.add(id(schema))

        for key, value in schema.items():
            if key == "$ref":
                referenced_schema = self._get_schema_by_id(value)
                if not self._validate_schema(referenced_schema):
                    return False
            elif key == "type":
                if value not in ["object", "array", "string", "integer", "number", "boolean", "null"]:
                    raise ValueError(f"Tipo no válido: {value}")
            elif key == "properties":
                if not isinstance(value, dict):
                    raise ValueError("Las propiedades deben ser un diccionario")
                for property_name, property_schema in value.items():
                    if not self._validate_schema(property_schema):
                        return False
            elif key == "items":
                if not isinstance(value, dict):
                    raise ValueError("Los items deben ser un diccionario")
                if not self._validate_schema(value):
                    return False

        self.visited_schemas.remove(id(schema))
        return True

    def validate(self, instance):
        """
        Valida una instancia contra el esquema.

        :param instance: La instancia a validar.
        :return: True si la instancia es válida, False de lo contrario.
        """
        if instance is None:
            raise ValueError("La instancia no puede ser None")

        if not isinstance(instance, dict):
            raise ValueError("La instancia debe ser un objeto JSON")

        return self._validate_schema(self.schema)


