        if threshold <= 0:
            raise ValueError("El umbral debe ser mayor que 0")
        if timeout <= 0:
            raise ValueError("El tiempo de espera debe ser mayor que 0")
        if backoff_factor <= 0:
            raise ValueError("El factor de backoff debe ser mayor que 0")
