    """

    def __init__(self, esquema):
        """
        Inicializa el validador con un esquema JSON.

        :param esquema: El esquema JSON a validar.
        """
        self.esquema = esquema
        self.visitados = set()

    def _es_json_valido(self, json_obj):
        """
        Verifica si un objeto es un JSON válido.

        :param json_obj: El objeto a verificar.
        :return: True si es un JSON válido, False de lo contrario.
        """
        try:
            json.dumps(json_obj)
            return True
        except TypeError:
            return False

    def _manejar_referencia_circular(self, referencia, esquema_actual):
        """
        Maneja una referencia circular en el esquema.

        :param referencia: La referencia circular encontrada.
        :param esquema_actual: El esquema actual que se está validando.
        :return: True si la referencia es válida, False de lo contrario.
        """
        if referencia in self.visitados:
            return False
        self.visitados.add(referencia)
        return self._validar_esquema(esquema_actual)

    def _validar_esquema(self, esquema):
        """
        Valida un esquema JSON.

        :param esquema: El esquema a validar.
        :return: True si el esquema es válido, False de lo contrario.
        """
        if not self._es_json_valido(esquema):
            return False
        for propiedad, valor in esquema.items():
            if isinstance(valor, dict) and "$ref" in valor:
                referencia = valor["$ref"]
                if not self._manejar_referencia_circular(referencia, esquema):
                    return False
        return True

