import json

class JsonValidator:
    """
    Clase para validar JSON contra un esquema.
    """

    def __init__(self, schema):
        """
        Inicializa el validador con un esquema.

        :param schema: El esquema contra el que se validará el JSON.
        """
        self.schema = schema
        self.visited = set()

    def _handle_circular_reference(self, schema):
        """
        Maneja las referencias circulares en el esquema.

        :param schema: El esquema que se está validando.
        :return: True si la referencia es circular, False de lo contrario.
        """
        if id(schema) in self.visited:
            return True
        self.visited.add(id(schema))
        return False

    def _validate_schema(self, schema, json_data):
        """
        Valida el esquema contra el JSON.

        :param schema: El esquema que se está validando.
        :param json_data: El JSON que se está validando.
        :return: True si el JSON es válido, False de lo contrario.
        """
        if schema is None or json_data is None:
            return False

        if schema.get("type") == "null":
            return json_data is None

        if schema.get("type") == "boolean":
            return isinstance(json_data, bool)

        if schema.get("type") == "object":
            for property_name, property_schema in schema.get("properties", {}).items():
                if property_name not in json_data:
                    if property_schema.get("required", False):
                        return False
                else:
                    if not self._validate_schema(property_schema, json_data[property_name]):
                        return False
            return True

        if schema.get("type") == "array":
            for item in json_data:
                if not self._validate_schema(schema.get("items", {}), item):
                    return False
            return True

        return isinstance(json_data, type(schema.get("type")))

    def _validate(self, json_data):
        """
        Valida el JSON contra el esquema.

        :param json_data: El JSON que se está validando.
        :return: True si el JSON es válido, False de lo contrario.
        """
        if self.schema is None or json_data is None:
            return False

        if self._handle_circular_reference(self.schema):
            return False

        return self._validate_schema(self.schema, json_data)

    def validate(self, json_data):
        """
        Valida el JSON contra el esquema.

        :param json_data: El JSON que se está validando.
        :return: True si el JSON es válido, False de lo contrario.
        """
        return self._validate(json_data)


