import hashlib
import functools

def cache_resultados(ttl=60):
    cache_sistema = {}

    def registrar_dependencia(funcion, args, kwargs):
        clave = _generar_clave(funcion, args, kwargs)
        cache_sistema[clave] = None

    def invalidar_cache(funcion, args, kwargs):
        clave = _generar_clave(funcion, args, kwargs)
        if clave in cache_sistema:
            del cache_sistema[clave]

    def _generar_clave(funcion, args, kwargs):
        args_str = str(args)
        kwargs_str = str(kwargs)
        clave = f"{funcion.__name__}:{args_str}:{kwargs_str}"
        return hashlib.sha256(clave.encode()).hexdigest()

    def decorador_cache(funcion):
        @functools.wraps(funcion)
        def wrapper(*args, **kwargs):
            clave = _generar_clave(funcion, args, kwargs)
            if clave in cache_sistema:
                return cache_sistema[clave]
            try:
                resultado = funcion(*args, **kwargs)
                cache_sistema[clave] = resultado
                return resultado
            except Exception as e:
                invalidar_cache(funcion, args, kwargs)
                raise e
        return wrapper
    return decorador_cache

# Ejemplo de uso
@cache_resultados(ttl=30)
