import time
from collections import OrderedDict

class Cache:
    def __init__(self, capacidad):
        if capacidad <= 0:
            raise ValueError("La capacidad del cache debe ser mayor que cero")
        self.capacidad = capacidad
        self.cache = OrderedDict()

    def agregar(self, clave, valor, tiempo_expiracion):
        if tiempo_expiracion <= 0:
            raise ValueError("El tiempo de expiración debe ser mayor que cero")
        if clave is None:
            raise ValueError("La clave no puede ser None")
        if valor is None:
            raise ValueError("El valor no puede ser None")
        if clave in self.cache:
            del self.cache[clave]
        elif len(self.cache) >= self.capacidad:
            self.cache.popitem(last=False)
        self.cache[clave] = (valor, time.time() + tiempo_expiracion)

    def acceder(self, clave):
        if clave not in self.cache:
            raise KeyError("La clave no existe en el cache")
        valor, tiempo_expiracion = self.cache[clave]
        if time.time() > tiempo_expiracion:
            del self.cache[clave]
            raise KeyError("La clave ha expirado")
        self.cache.move_to_end(clave)
        return valor

    def eliminar(self, clave):
        if clave not in self.cache:
            raise KeyError("La clave no existe en el cache")
        del self.cache[clave]

    def verificar_expiracion(self):
        ahora = time.time()
        claves_expiradas = [clave for clave, (_, tiempo_expiracion) in self.cache.items() if tiempo_expiracion < ahora]
        for clave in claves_expiradas:
            del self.cache[clave]

def main():
    cache = Cache(5)
    cache.agregar("clave1", "valor1", 10)
    cache.agregar("clave2", "valor2", 5)
    print(cache.acceder("clave1"))
    cache.verificar_expiracion()
    cache.eliminar("clave2")
    try:
        print(cache.acceder("clave2"))
    except KeyError as e:
        print(e)

if __name__ == "__main__":
