def groupby_manual(lista, clave):
    if not lista:
        return

    clave_actual = clave(lista[0])
    grupo_actual = [lista[0]]

    for elemento in lista[1:]:
        clave_elemento = clave(elemento)
        if clave_elemento == clave_actual:
            grupo_actual.append(elemento)
        else:
            yield clave_actual, grupo_actual
            clave_actual = clave_elemento
            grupo_actual = [elemento]

    yield clave_actual, grupo_actual

def main():
    lista = [1, 2, 2, 3, 3, 3, 4, 4, 4, 4]
    clave = lambda x: x

    for clave_grupo, grupo in groupby_manual(lista, clave):
        print(f"Clave: {clave_grupo}")
        for elemento in grupo:
            print(f" - {elemento}")

if __name__ == "__main__":
    main()
